const topicItem = $('Get Pending Topic').first().json;
const lenderItems = $input.all().map(item => item.json);

const lenders = lenderItems.map((l, index) => ({
  rank: index + 1,
  lender_name: l.lender_name || '',
  product_type: l.product_type || '',
  loan_category: l.loan_category || '',
  roi: {
    min_roi: l.roi_min || l.min_roi || l.interest_rate_start || null,
    max_roi: l.roi_max || l.max_roi || null
  },
  ltv: {
    max_ltv: l.ltv_max_overall || l.max_ltv || null,
    sorp: l.ltv_sorp || null,
    socp: l.ltv_socp || null,
    soip: l.ltv_soip || null,
    land: l.ltv_land || null
  },
  cibil: l.min_cibil || l.cibil_policy || '',
  city_coverage: l.city_allowed || l.cities_allowed || l.city_coverage || l.city || '',
  property_policy: {
    property_types: l.property_types || '',
    property_allowed: l.property_allowed || '',
    jda: l.title_jda || '',
    rhb: l.title_rhb || '',
    society_patta: l.title_society_patta || '',
    society_patta_year: l.title_society_patta_year || '',
    gram_panchayat: l.title_gram_panchayat || '',
    nagar_nigam: l.title_nagar_nigam || '',
    riico: l.title_riico || ''
  },
  income_policy: {
    income_types: l.income_types || l.income_types_allowed || '',
    profile_allowed: l.profile_allowed || '',
    programs: l.programs || '',
    surrogate_banking: l.surrogate_banking || '',
    surrogate_gst: l.surrogate_gst || '',
    surrogate_itr: l.surrogate_itr || '',
    surrogate_rtr: l.surrogate_rtr || '',
    surrogate_low_ltv: l.surrogate_low_ltv || '',
    surrogate_lip: l.surrogate_lip || ''
  },
  fees: {
    processing_fee_pct: l.processing_fee_pct || null,
    processing_fee_flat: l.processing_fee_flat || null
  },
  geo_limit: l.geo_limit || l.geo_limit_km || '',
  notes: l.notes || '',
  rag_text: l.rag_text || '',
  searchable_text: l.searchable_text || '',
  updated_at: l.updated_at || ''
}));

return [
  {
    json: {
      topic_id: topicItem.id,
      topic: topicItem.topic,
      target_keyword: topicItem.target_keyword,
      city: topicItem.city,
      loan_product: topicItem.loan_product,
      content_type: topicItem.content_type,
      source_reason: topicItem.source_reason,
      lender_count: lenders.length,
      lenders
    }
  }
];

const input = $json;

const systemPrompt = `You are WealthMetre's SEO content strategist and loan advisory content writer.

Write practical, India-specific, Jaipur/Rajasthan-focused loan content.

Rules:
- Output only valid JSON.
- Do not use markdown outside JSON.
- Do not invent lender policies.
- Use lender context only where relevant.
- If lender data is incomplete, explain generally instead of making false claims.
- Tone: helpful, trustworthy, simple English with light Hinglish where natural.
- Avoid guaranteeing approval, lowest rate, or fixed eligibility.
- Add disclaimer that final eligibility depends on lender policy, credit profile, income, property type, legal/technical checks, and documentation.
- Mention WealthMetre naturally as an AI-powered loan advisory platform comparing 140+ banks and NBFCs.`;

const userPrompt = `Generate a complete SEO blog draft as JSON using this input:

${JSON.stringify(input, null, 2)}

Return valid JSON with exactly these keys:

{
  "title": "",
  "slug": "",
  "meta_title": "",
  "meta_description": "",
  "focus_keyword": "",
  "city": "",
  "loan_product": "",
  "intro": "",
  "sections": [
    {
      "heading": "",
      "body": ""
    }
  ],
  "faq": [
    {
      "question": "",
      "answer": ""
    }
  ],
  "cta": "",
  "disclaimer": "",
  "suggested_internal_links": [],
  "suggested_schema_type": "BlogPosting"
}

Content requirements:
- Blog length should be around 1000 to 1400 words.
- Use clear headings.
- Include practical borrower examples for Jaipur.
- Include lender context only if supported by given data.
- Explain property title / income / CIBIL / LTV / ROI factors where relevant.
- Include 5 FAQs.
- CTA should invite user to use Diva AI Loan Advisor on WealthMetre.
- Slug should be lowercase and URL-friendly.`;

return {
  json: {
    topic_id: input.topic_id,
    topic: input.topic,
    requestBody: {
      model: "gpt-4o-mini",
      temperature: 0.4,
      response_format: {
        type: "json_object"
      },
      messages: [
        {
          role: "system",
          content: systemPrompt
        },
        {
          role: "user",
          content: userPrompt
        }
      ]
    }
  }
};

const topicId = $('Build OpenAI Request').first().json.topic_id;
const topic = $('Build OpenAI Request').first().json.topic;

let content = $json.choices?.[0]?.message?.content || '';

content = content.trim();

// Safety cleanup in case model ever wraps JSON in code fences
content = content
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let blog;

try {
  blog = JSON.parse(content);
} catch (error) {
  throw new Error('Failed to parse OpenAI JSON: ' + error.message + '\nRaw content: ' + content.slice(0, 500));
}

return {
  json: {
    topic_id: topicId,
    original_topic: topic,
    title: blog.title || '',
    slug: blog.slug || '',
    meta_title: blog.meta_title || '',
    meta_description: blog.meta_description || '',
    focus_keyword: blog.focus_keyword || '',
    city: blog.city || '',
    loan_product: blog.loan_product || '',
    intro: blog.intro || '',
    sections: blog.sections || [],
    faq: blog.faq || [],
    cta: blog.cta || '',
    disclaimer: blog.disclaimer || '',
    suggested_internal_links: blog.suggested_internal_links || [],
    suggested_schema_type: blog.suggested_schema_type || 'BlogPosting',
    full_json: blog
  }
};

const blog = $json;

function cleanText(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function renderLongContent(blog) {
  let out = '';

  out += `# ${cleanText(blog.title)}\n\n`;

  if (blog.intro) {
    out += `${cleanText(blog.intro)}\n\n`;
  }

  if (Array.isArray(blog.sections)) {
    for (const section of blog.sections) {
      out += `## ${cleanText(section.heading)}\n\n`;
      out += `${cleanText(section.body)}\n\n`;
    }
  }

  if (Array.isArray(blog.faq) && blog.faq.length) {
    out += `## FAQs\n\n`;
    for (const item of blog.faq) {
      out += `### ${cleanText(item.question)}\n\n`;
      out += `${cleanText(item.answer)}\n\n`;
    }
  }

  if (blog.cta) {
    out += `## Next Step\n\n${cleanText(blog.cta)}\n\n`;
  }

  if (blog.disclaimer) {
    out += `## Disclaimer\n\n${cleanText(blog.disclaimer)}\n\n`;
  }

  return out.trim();
}

const contentLong = renderLongContent(blog);

return {
  json: {
    topic_id: blog.topic_id,
    content_type: 'blog',
    topic: cleanText(blog.original_topic || blog.title),
    target_keyword: cleanText(blog.focus_keyword),
    city: cleanText(blog.city || 'Jaipur'),
    loan_product: cleanText(blog.loan_product),
    source_table: 'seo_content_topics,lenders_products',
    source_record_ids: JSON.stringify({
      topic_id: blog.topic_id
    }),
    title: cleanText(blog.title),
    meta_title: cleanText(blog.meta_title),
    meta_description: cleanText(blog.meta_description),
    slug: cleanText(blog.slug),
    content_long: contentLong,
    content_short: cleanText(blog.intro).slice(0, 1000),
    hashtags: '',
    cta: cleanText(blog.cta),
    image_prompt: `Create a clean professional blog image for WealthMetre about ${cleanText(blog.title)} in Jaipur. Use finance, property, and AI loan advisory theme. No text overlay.`,
    status: 'needs_review',
    ai_score: 0,
    compliance_notes: cleanText(blog.disclaimer),
    full_json: blog.full_json
  }
};

const topicRow = $('Build Content Queue Row').first().json;
const openAiRequest = $('Build OpenAI Request').first().json.requestBody;
const parsedBlog = $('Parse Blog JSON').first().json;

function sqlEscape(value) {
  if (value === null || value === undefined) return 'NULL';
  return "'" + String(value)
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "\\'")
    .replace(/\0/g, '\\0')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r')
    .replace(/\x1a/g, '\\Z') + "'";
}

const promptUsed = JSON.stringify({
  model: openAiRequest.model,
  temperature: openAiRequest.temperature,
  messages: openAiRequest.messages
});

const aiResponse = JSON.stringify(parsedBlog.full_json || parsedBlog);

const logSql = `
INSERT INTO content_generation_logs (
  workflow_name,
  content_type,
  source_id,
  status,
  prompt_used,
  ai_response,
  error_message
) VALUES (
  'WM - Blog Generator MVP',
  ${sqlEscape(topicRow.content_type || 'blog')},
  ${Number(topicRow.topic_id || 0)},
  'success',
  ${sqlEscape(promptUsed)},
  ${sqlEscape(aiResponse)},
  NULL
);
`;

return {
  json: {
    topic_id: topicRow.topic_id,
    log_sql: logSql
  }
};
